@import "tailwindcss";

@theme {
  /* palette (mined, ranked by usage) */
  --color-neutral-50: #ffffff;
  --color-neutral-400: #9198a1;
  --color-neutral-500: #818b98;
  --color-neutral-700: #59636e;
  --color-neutral-800: #3d444d;
  --color-neutral-900: #25292e;
  --color-deep-blue: #010409;
  --color-pale-cyan: #eff2f5;
  --color-deep-cyan: #151b23;
  --color-cyan: #d1d9e0;
  --color-pale-orange: #eeeae2;
  --color-blue: #0349b4;
  --color-deep-red: #271817;
  --color-cyan-2: #0969da;
  --color-cyan-3: #5cacff;
  --color-blue-2: #023b95;
  --color-pale-cyan-2: #d1f0ff;
  --color-blue-3: #b7bdc8;

  /* inferred semantic roles (each maps to a distinct mined value) */
  --color-canvas: #25292e;
  --color-ink: #ffffff;
  --color-text-muted: #818b98;
  --color-surface: #3d444d;
  --color-hairline: #59636e;
  --color-accent: #010409;
  --color-accent-2: #eff2f5;
  --color-accent-3: #151b23;
}

/* dark-mode values mined from the source (native token names) */
@media (prefers-color-scheme: dark) {
  :root {
    --bgColor-success-emphasis: #1f883d;
    --button-outline-bgColor-active: #0757ba;
    --button-primary-bgColor-active: #197935;
    --button-primary-bgColor-disabled: #95d8a6;
    --button-primary-bgColor-hover: #1c8139;
    --buttonCounter-danger-fgColor-rest: #c21c2c;
    --color-ansi-cyan: #1b7c83;
    --color-ansi-cyan-bright: #3192aa;
    --control-checked-bgColor-active: #0757ba;
    --control-checked-bgColor-hover: #0860ca;
    --fgColor-danger: #d1242f;
    --reactionButton-selected-bgColor-hover: #caecff;
    --avatarStack-fade-bgColor-default: #c8d1da;
    --avatarStack-fade-bgColor-muted: #dae0e7;
    --bgColor-accent-emphasis: #0969da;
    --bgColor-accent-muted: #ddf4ff;
    --bgColor-attention-emphasis: #9a6700;
    --bgColor-attention-muted: #fff8c5;
    --bgColor-danger-emphasis: #cf222e;
    --bgColor-danger-muted: #ffebe9;
    --bgColor-disabled: #eff2f5;
    --bgColor-done-emphasis: #8250df;
    --bgColor-done-muted: #fbefff;
    --bgColor-emphasis: #25292e;
    --bgColor-inverse: #25292e;
    --bgColor-muted: #f6f8fa;
    --bgColor-neutral-emphasis: #59636e;
    --bgColor-neutral-muted: #818b981f;
    --bgColor-open-emphasis: var(--bgColor-success-emphasis);
    --bgColor-severe-emphasis: #bc4c00;
    --bgColor-severe-muted: #fff1e5;
    --bgColor-sponsors-emphasis: #bf3989;
    --bgColor-sponsors-muted: #ffeff7;
    --bgColor-success-muted: #dafbe1;
    --bgColor-transparent: #fff0;
    --borderColor-accent-emphasis: #0969da;
    --borderColor-accent-muted: #54aeff66;
    --borderColor-attention-emphasis: #9a6700;
    --borderColor-attention-muted: #d4a72c66;
    --borderColor-danger-emphasis: #cf222e;
    --borderColor-danger-muted: #ff818266;
    --borderColor-default: #d1d9e0;
    --borderColor-disabled: #818b981a;
    --borderColor-done-emphasis: #8250df;
    --borderColor-done-muted: #c297ff66;
    --borderColor-emphasis: #818b98;
    --borderColor-neutral-emphasis: #59636e;
    --borderColor-severe-emphasis: #bc4c00;
    --borderColor-severe-muted: #fb8f4466;
    --borderColor-sponsors-emphasis: #bf3989;
    --borderColor-sponsors-muted: #ff80c866;
    --borderColor-success-emphasis: #1a7f37;
    --borderColor-success-muted: #4ac26b66;
    --borderColor-transparent: #fff0;
    --button-danger-bgColor-active: #a40e26;
    --button-danger-fgColor-disabled: #d1242f80;
    --button-danger-fgColor-rest: var(--fgColor-danger);
    --button-danger-shadow-selected: inset 0 1px 0 0 #4c001433;
    --button-inactive-bgColor: #e6eaef;
    --button-inactive-fgColor: #59636e;
  }
}

